// .commitlintrc.js
// npm install --save-dev @commitlint/cli @commitlint/config-conventional

/** @type {import('@commitlint/types').UserConfig} */
module.exports = {
  extends: ['@commitlint/config-conventional'],
  rules: {
    'type-enum': [
      2,  // error level: 2 = error, 1 = warning, 0 = off
      'always',
      [
        // Standard Conventional Commits types
        'feat',
        'fix',
        'refactor',
        'perf',
        'docs',
        'test',
        'chore',
        'ci',
        'revert',
        'build',
        // GenAI-extended types
        'prompt',
        'eval',
        'safety',
        'model',
        'agent',
      ],
    ],
    // Require body for safety and prompt commits
    'body-empty': [1, 'never'],  // warning if body is missing
    // Enforce scope format: lowercase, hyphens only
    'scope-case': [2, 'always', 'kebab-case'],
    'subject-case': [2, 'always', ['sentence-case', 'lower-case']],
    'header-max-length': [2, 'always', 72],
  },
};

npm install --save-dev commitizen cz-conventional-changelog

# In package.json, add:
# "config": {
#   "commitizen": {
#     "path": "./scripts/cz-genai-adapter.js"
#   }
# }

# Then run with:
# git cz
# or via npx:
# npx cz
